const schema = { /* ... */ };
const valid = ajv.validate(schema, data);
if (!valid) throw new Error("資料不合法");

lessons.content:
## 安裝
```bash
npm install zod
```

## 基本使用
```typescript
import { z } from "zod";

const UserSchema = z.object({
  name: z.string().min(1).max(100),
  age: z.number().int().min(0).max(150),
  email: z.string().email(),
  tags: z.array(z.string()).min(1),
  role: z.enum(["admin", "user", "guest"]),
});

// 自動推斷 TS 型別
type User = z.infer<typeof UserSchema>;

// 驗證
const result = UserSchema.safeParse(data);
if (result.success) {
  console.log(result.data);  // type-safe User
} else {
  console.log(result.error.format());
}
```

## 進階組合
```typescript
// 巢狀
const PostSchema = z.object({
  title: z.string(),
  author: UserSchema,  // 重用
  comments: z.array(z.object({
    text: z.string(),
    userId: z.string().uuid(),
  })),
});

// Optional / Nullable
z.object({
  name: z.string().optional(),    // name?: string
  bio: z.string().nullable(),     // bio: string | null
  avatar: z.string().nullish(),   // avatar?: string | null
});

// Default
z.object({
  role: z.enum(["admin", "user"]).default("user"),
});

// 轉換 + 驗證
z.string()
  .transform(s => s.trim().toLowerCase())
  .pipe(z.string().email());

// Discriminated union（聯合型別）
const Shape = z.discriminatedUnion("type", [
  z.object({ type: z.literal("circle"), radius: z.number() }),
  z.object({ type: z.literal("square"), side: z.number() }),
]);
```

## 常用驗證
```typescript
z.string().email();
z.string().url();
z.string().uuid();
z.string().regex(/^09\d{8}$/);  // 台灣手機
z.string().min(8).max(32);
z.string().datetime();
z.number().positive();
z.number().int();
z.number().multipleOf(0.5);
z.array(z.string()).nonempty();
z.date().min(new Date("2026-01-01"));
```

## 整合 React Hook Form
```typescript
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";

const { register, handleSubmit, formState: { errors } } = useForm<User>({
  resolver: zodResolver(UserSchema),
});
```

## 整合 Next.js Server Action
```typescript
"use server";
import { z } from "zod";

const SignupSchema = z.object({
  email: z.string().email(),
  password: z.string().min(8),
});

export async function signup(formData: FormData) {
  const data = SignupSchema.parse(Object.fromEntries(formData));
  // data 是 type-safe
}
```

**☕ 用人話講**

Zod 是 **TypeScript 最友善的驗證工具**——比傳統 JSON Schema 簡潔很多，而且寫一份規格就能**自動推導出 TS 型別**（驗證跟型別一次到位）。**一句話記住**：像一張表格同時當「填寫須知」又自動生出「資料庫欄位」——寫一次、兩邊都顧到，一魚兩吃。

