## 1. 共用 Schema（Single Source of Truth）
```typescript
// lib/schemas.ts
import { z } from "zod";

export const CreateUserSchema = z.object({
  username: z.string().min(3).max(30),
  email: z.string().email(),
  age: z.number().int().min(13).max(150),
  role: z.enum(["member", "admin"]).default("member"),
});

export type CreateUserInput = z.infer<typeof CreateUserSchema>;

export const UserSchema = CreateUserSchema.extend({
  id: z.string().uuid(),
  createdAt: z.date(),
});
export type User = z.infer<typeof UserSchema>;
```

## 2. tRPC Router
```typescript
// server/routers/user.ts
import { router, publicProcedure } from "../trpc";
import { CreateUserSchema } from "@/lib/schemas";
import { db } from "@/lib/db";

export const userRouter = router({
  list: publicProcedure
    .query(async () => {
      return await db.user.findMany();
    }),

  byId: publicProcedure
    .input(z.string().uuid())
    .query(async ({ input }) => {
      const user = await db.user.findUnique({ where: { id: input } });
      if (!user) throw new TRPCError({ code: "NOT_FOUND" });
      return user;
    }),

  create: publicProcedure
    .input(CreateUserSchema)
    .mutation(async ({ input }) => {
      return await db.user.create({ data: input });
    }),
});
```

## 3. Next.js App Router 整合
```typescript
// app/api/trpc/[trpc]/route.ts
import { fetchRequestHandler } from "@trpc/server/adapters/fetch";
import { appRouter } from "@/server/router";

const handler = (req: Request) =>
  fetchRequestHandler({
    endpoint: "/api/trpc",
    req,
    router: appRouter,
    createContext: () => ({}),
  });

export { handler as GET, handler as POST };
```

## 4. Client Hook
```typescript
// lib/trpc-client.ts
import { createTRPCReact } from "@trpc/react-query";
import type { AppRouter } from "@/server/router";

export const trpc = createTRPCReact<AppRouter>();
```

## 5. 前端表單（含 Zod 驗證）
```typescript
// app/users/create/page.tsx
"use client";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { CreateUserSchema, type CreateUserInput } from "@/lib/schemas";
import { trpc } from "@/lib/trpc-client";

export default function CreatePage() {
  const { register, handleSubmit, formState: { errors } } = useForm<CreateUserInput>({
    resolver: zodResolver(CreateUserSchema),
  });
  const create = trpc.user.create.useMutation();

  return (
    <form onSubmit={handleSubmit(data => create.mutate(data))}>
      <input {...register("username")} />
      {errors.username && <p>{errors.username.message}</p>}

      <input {...register("email")} />
      {errors.email && <p>{errors.email.message}</p>}

      <input type="number" {...register("age", { valueAsNumber: true })} />
      {errors.age && <p>{errors.age.message}</p>}

      <button type="submit" disabled={create.isPending}>
        {create.isPending ? "建立中..." : "建立"}
      </button>
    </form>
  );
}
```

## 完整型別流
```
[Zod schema]
    ↓
[TS Type 自動推斷]
    ↓
[tRPC Server Procedure]
    ↓
[tRPC Client Type-Safe]
    ↓
[React Hook Form + Zod Resolver]
    ↓
[使用者輸入]
```

任何一層型別不符 = TS 編譯錯誤 = bug 提前抓到。

## 完整檢查
- ✅ 一份 schema、5 個地方共用
- ✅ Server 驗證、Client 驗證
- ✅ TS 型別 100% 同步
- ✅ Runtime 也驗證（不只編譯時）
- ✅ 錯誤訊息可中文化
- ✅ Server / Client 都 type-safe

**☕ 用人話講**

全章總整合實戰：用 **Zod schema 共用 + tRPC 連起前後端**，做一個 **型別從頭安全到尾的 Next.js API**。**一句話記住**：像期末作品——把整章學的（格式、驗證、型別安全、文件）全用上，做出一個「資料絕對不會出錯」的完整成品，這就是專業後端的樣子。

